import React, { useState } from "react";

function App() {
  const [name, setName] = useState("");

  const handleGenerate = async (e) => {
    e.preventDefault();
    if (!name) {
      alert("Please enter your name");
      return;
    }

    const response = await fetch("http://localhost:5000/generate-certificate", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ name }),
    });

    const blob = await response.blob();
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement("a");
    a.href = url;
    a.download = `${name}-certificate.pdf`;
    document.body.appendChild(a);
    a.click();
    a.remove();
  };

  return (
    <div className="min-h-screen my-5 flex items-center p-5 justify-center bg-gradient-to-br from-blue-50 to-indigo-100 px-4">
      <div className="bg-white rounded-2xl  ps-5shadow-xl p-8 w-full  my-5 max-w-md sm:max-w-lg md:max-w-xl text-center">
        <h1 className="text-3xl sm:text-4xl font-bold text-indigo-800 mb-4">
          🎓 Certificate Generator
        </h1>
        <p className="text-gray-600 mb-6 p-5 text-sm sm:text-base">
          Enter your name below to generate your custom certificate.
        </p>

        <div className="flex justify-center px-4">
          <form
            onSubmit={handleGenerate}
            className="w-full max-w-md text-center"
          >
            <input
              type="text"
              placeholder="Enter your name"
              value={name}
              onChange={(e) => setName(e.target.value)}
              style={{ padding: "10px", width: "300px" }}
            />
            <br />
            <br />
            <button type="submit" style={{ padding: "10px 20px" }}>
              Generate Certificate
            </button>
          </form>
        </div>
      </div>
    </div>
  );
}

export default App;
